import React, { useState } from 'react';
import './App.css';

const App = () => {
  const [input, setInput] = useState('');
  const [result, setResult] = useState('');
  const [loading, setLoading] = useState(false);
  const [error, setError] = useState('');

  const quickTags = ["Deductible", "Premium", "Copay", "Out-of-Pocket Max", "HSA", "PPO vs HMO"];

  const decode = async (term) => {
    const query = term || input.trim();
    if (!query) return;
    setLoading(true);
    setError('');
    setResult('');

    try {
      const response = await fetch('https://api.anthropic.com/v1/messages', {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
          'x-api-key': process.env.REACT_APP_ANTHROPIC_API_KEY,
          'anthropic-version': '2023-06-01',
          'anthropic-dangerous-direct-browser-access': 'true',
        },
        body: JSON.stringify({
          model: 'claude-sonnet-4-5',
          max_tokens: 1024,
          system: `You are InsurePlain, an expert insurance decoder. Your job is to explain insurance terms, policy clauses, fine print, and jargon in plain English. When given an insurance term or concept:
1. Give a clear, simple one-sentence definition
2. Explain what it means for the policyholder in practical terms
3. Give a real-world example
4. Note any important gotchas or things to watch out for
Keep your tone friendly, clear, and jargon-free. You are not providing legal or financial advice.`,
          messages: [{ role: 'user', content: `Explain this insurance term or concept: ${query}` }],
        }),
      });

      const data = await response.json();
      if (data.content && data.content[0]) {
        setResult(data.content[0].text);
      } else {
        setError('Something went wrong. Please try again.');
      }
    } catch (err) {
      setError('Something went wrong. Please try again.');
    }
    setLoading(false);
  };

  return (
    <div className="app-wrapper">
      <header className="site-header">
        <div className="header-inner">
          <div className="logo">InsurePlain</div>
          <p className="tagline">Insurance fine print, finally explained.</p>
        </div>
      </header>

      <main className="main-content">
        <section className="hero-section">
          <div className="container">
            <h1 className="hero-title">Understand your policy.<br />No broker required.</h1>
            <p className="hero-sub">Type any insurance term, clause, or policy language and get a plain-English breakdown — what it means, how it affects you, and what to watch out for.</p>

            <div className="disclaimer-banner">
              <span className="disclaimer-icon">⚠️</span>
              <p>For educational purposes only. InsurePlain does not provide legal or financial advice. Always consult a licensed insurance professional about your specific situation.</p>
            </div>

            <div className="decoder-card">
              <div className="input-row">
                <input
                  type="text"
                  className="decode-input"
                  placeholder="Enter an insurance term, clause, or concept"
                  value={input}
                  onChange={(e) => setInput(e.target.value)}
                  onKeyDown={(e) => e.key === 'Enter' && decode()}
                />
                <button className="decode-btn" onClick={() => decode()} disabled={loading}>
                  {loading ? 'Decoding...' : 'Decode'}
                </button>
              </div>

              <div className="quick-tags">
                <span className="quick-label">Common:</span>
                {quickTags.map((tag) => (
                  <button key={tag} className="tag-btn" onClick={() => { setInput(tag); decode(tag); }}>
                    {tag}
                  </button>
                ))}
              </div>

              {error && <div className="error-msg">⚠️<br />{error}</div>}

              {result && (
                <div className="result-box">
                  <div className="result-content">{result}</div>
                </div>
              )}
            </div>
          </div>
        </section>
      </main>

      <footer className="site-footer">
        <div className="container">
          <p>Not a substitute for professional insurance or legal advice.</p>
          <p>© 2025 InsurePlain. All rights reserved.</p>
        </div>
      </footer>
    </div>
  );
};

export default App;
